  auto MatchBinOp = [&](unsigned ShOpnum) -> Instruction * {
    Constant *CMask, *CShift;
    Value *X, *Y, *ShiftedX, *Mask, *Shift;
    if (!match(I.getOperand(ShOpnum),
               m_OneUse(m_Shift(m_Value(Y), m_Value(Shift)))))
      return nullptr;
    if (!match(I.getOperand(1 - ShOpnum),
               m_BinOp(m_Value(ShiftedX), m_Value(Mask))))
      return nullptr;

    if (!match(ShiftedX, m_OneUse(m_Shift(m_Value(X), m_Specific(Shift)))))
      return nullptr;

    // Make sure we are matching instruction shifts and not ConstantExpr
    auto *IY = dyn_cast<Instruction>(I.getOperand(ShOpnum));
    auto *IX = dyn_cast<Instruction>(ShiftedX);
    if (!IY || !IX)
      return nullptr;

    // LHS and RHS need same shift opcode
    unsigned ShOpc = IY->getOpcode();
    if (ShOpc != IX->getOpcode())
      return nullptr;

    // Make sure binop is real instruction and not ConstantExpr
    auto *BO2 = dyn_cast<Instruction>(I.getOperand(1 - ShOpnum));
    if (!BO2)
      return nullptr;

    // Check if the binop is xor and the mask is invariant under shift
    if (BO2->getOpcode() != Instruction::Xor)
      return nullptr;

    // We now have: (X << S) ^ M and Y << S, and want to form (X ^ Y) << S ^ M
    // This is valid only if the shifted-out bits of M are zero, but we can
    // always do it for xor since (A << S) ^ (B << S) == (A ^ B) << S.
    // So we can reassociate: ((X << S) ^ M) ^ (Y << S) => ((X << S) ^ (Y << S)) ^ M => (X ^ Y) << S ^ M
    Instruction *NewXor = BinaryOperator::CreateXor(X, Y);
    Instruction *NewShift = BinaryOperator::Create(ShOpc, NewXor, Shift);
    Instruction *NewXor2 = BinaryOperator::CreateXor(NewShift, Mask);
    NewXor->setDebugLoc(I.getDebugLoc());
    NewShift->setDebugLoc(I.getDebugLoc());
    NewXor2->setDebugLoc(I.getDebugLoc());

    // Replace current instruction with NewXor2 and return it
    I.replaceAllUsesWith(NewXor2);
    I.eraseFromParent();
    return NewShift;  // Return non-null to indicate success
  };
